There is a bug in the following code where self.entries is a list and the each entry in the list is a dict, however you are trying to fetch the entry in the list by the value of the entry and not by index.
You need to fetch the dict which has the value of the entry and then extend the synonyms 
```python
def add_entry(self, value, synonyms=[]):
        if self.isEnum:
            entry = {'value': value, 'synonyms': value}
        entry = {'value': value, 'synonyms': synonyms}
        self.entries.append(entry)


    def add_synonyms(self, entry, synonyms):
        self.entries[entry].extend(synonyms)
```

hello @miguelgrinberg :+1: 

I want to send ArrayBuffer between client and server using socket.io. when I send buffer size in 10**8, the connection is broken. but when size is 10 , it's OK. 

I want to know why, when the buffer size is large, the broken happens.  

- **packages**
  - sanic == 0.6.0
  - socketio == 1.8.1

**code** 
- HTML
```html
<!DOCTYPE HTML>
<html>
  <head>
    <title> Sanic with ArrayBuffer </title>
    <meta charset="utf-8">
    <script src="https://cdnjs.cloudflare.com/ajax/libs/socket.io/2.0.3/socket.io.js"></script>

  </head>
  <body>
    <script type='text/javascript' charset="utf-8">
      window.onload = ()=>{
        console.log('loading');

        const namespace = '/arraybuffer';
        const host      = window.location.origin;
        const socket    = io.connect(host+namespace);

        socket.on('connect',(msg)=>{
          console.log('connect :', msg);

          if (Boolean(msg)){
            const event   = 'arraybuffer';
            // const length  = 10**1;
            const length  = 10**8;
            let   content = new ArrayBuffer(length);
            let   data    = {
              content: content,
              length: content.byteLength,
            };
            socket.emit(event,data);
          }

        });

        socket.on('disconnect',(msg)=>{
          console.log('disconnect :', msg);
        });

        socket.on('arraybuffer', (msg)=>{
          console.log('arraybuffer :', msg);
        });
      }
    </script>
  </body>
</html>

```  

- sanic server 

```python
# -*- coding: utf-8 -*-
#

import os
import sys
import asyncio

from sanic import Sanic
from sanic.response import html, json
import socketio
import aiofiles

import numpy as np

root = os.path.dirname(os.path.abspath(__file__))

app = Sanic(__name__)
sio = socketio.AsyncServer(async_mode='sanic',
                           engineio_logger=True,
                           logger=True)
sio.attach(app)

@app.route('/')
async def index(request):
    filename = os.path.join(root, 'index.html')
    response = json({'hello':'sanic with ArrayBuffer'})

    if os.path.exists(filename) and os.path.isfile(filename):
        async with aiofiles.open(filename, 'r') as f:
            content = await f.read()
        response = html(content)

    return response

app.static('/', root)

namespace = '/arraybuffer'

@sio.on('connect', namespace=namespace)
async def on_connect(sid, environ):
    print('client :{} is connected'.format(sid))
    await sio.emit('connect',{'client':sid,'message':'connected'},room=sid,namespace=namespace)

@sio.on('disconnect', namespace=namespace)
async def on_disconnect(sid):
    print('client : {} is disconnected'.format(sid))


@sio.on('arraybuffer', namespace=namespace)
async def on_arraybuffer(sid, message):
    event = 'arraybuffer'
    print(event)
    print(list(message.keys()))

    data = {
        'client':sid,
        'data':list(message.keys()),
    }
    await sio.emit(event,data,room=sid,namespace=namespace)


if __name__ == '__main__':
    app.run(host='127.0.0.1', port=9876, debug=True, workers=1)

```

